diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 7bff13d59528..f7c061a6ff54 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -1849,6 +1849,35 @@ static Value *simplifyAndOrOfFCmps(const SimplifyQuery &Q, FCmpInst *LHS,
                  ? static_cast<Value *>(LHS)
                  : ConstantInt::getBool(LHS->getType(), !IsAnd);
   }
+  // (X pred C0) | (X pred C1) --> X pred C_looser
+  // (X pred C0) & (X pred C1) --> X pred C_stricter
+  // where one comparison implies the other (same predicate, same LHS operand)
+  if (LHS0 == RHS0 && PredL == PredR) {
+    const APFloat *C0, *C1;
+    if (match(LHS1, m_APFloat(C0)) && match(RHS1, m_APFloat(C1)) &&
+        &C0->getSemantics() == &C1->getSemantics()) {
+      // For 'less than' predicates (olt/ole/ult/ule), smaller constant implies
+      // larger constant. For 'greater than' predicates (ogt/oge/ugt/uge),
+      // larger constant implies smaller constant.
+      if (PredL == FCmpInst::FCMP_OLT || PredL == FCmpInst::FCMP_OLE ||
+          PredL == FCmpInst::FCMP_ULT || PredL == FCmpInst::FCMP_ULE) {
+        // For less-than: C0 <= C1 means LHS implies RHS
+        if (*C0 <= *C1)
+          return IsAnd ? static_cast<Value *>(LHS) : static_cast<Value *>(RHS);
+        if (*C1 <= *C0)
+          return IsAnd ? static_cast<Value *>(RHS) : static_cast<Value *>(LHS);
+      } else if (PredL == FCmpInst::FCMP_OGT ||
+                 PredL == FCmpInst::FCMP_OGE ||
+                 PredL == FCmpInst::FCMP_UGT ||
+                 PredL == FCmpInst::FCMP_UGE) {
+        // For greater-than: C0 >= C1 means LHS implies RHS
+        if (*C0 >= *C1)
+          return IsAnd ? static_cast<Value *>(LHS) : static_cast<Value *>(RHS);
+        if (*C1 >= *C0)
+          return IsAnd ? static_cast<Value *>(RHS) : static_cast<Value *>(LHS);
+      }
+    }
+  }

   return nullptr;
 }

